<template>
    <div class="myHeader">
        <el-button
            text
            @click="handler"
            :style="{
				transform: menuToggle ? 'rotate(0)' : 'rotate(180deg)',
			}"
        >
            <el-icon>
                <Expand />
            </el-icon>
        </el-button>
    </div>
</template>

<script setup>
const { computed } = require("@vue/runtime-core");
const { useStore } = require("vuex");
const store = useStore();

const menuToggle = computed(() => {
    return store.state.menuToggle;
});
const handler = () => {
    store.commit("menuToggle");
};
</script>

<style scoped>
.el-button {
    font-size: 22px;
}
</style>
