<template>
    <div>
        <div class="player blur" :style="{left: flag ? '83px':'210px'}">
            <div class="player_left">
                <el-image
                    :src="pic"
                    v-loading="audioLoading"
                    element-loading-background="rgba(122, 122, 122, 0.8)"
                >
                    <template #error>
                        <div class="image-slot">
                            <el-icon>
                                <Picture />
                            </el-icon>
                        </div>
                    </template>
                </el-image>
                <div class="player_info">
                    <h3>{{ nowPlay.song }}</h3>
                    <p>{{ nowPlay.singer }}</p>
                </div>
            </div>
            <ul class="player_btn">
                <li>
                    <i class="ri-skip-back-line"></i>
                </li>
                <li @click="playBtn">
                    <i :class="playBtnIcon"></i>
                </li>
                <li>
                    <i class="ri-skip-forward-line"></i>
                </li>
            </ul>
            <ul class="player_btn">
                <li style="font-size: 28px" @click="playlistToggle">
                    <i class="ri-play-list-line"></i>
                </li>
            </ul>
        </div>
        <Playlist />
        <audio id="Audio" :src="url" autoplay style="display:none" />
    </div>
</template>
<script setup>
import Playlist from "@/components/playlist/Index.vue";
import { ref, computed, onMounted, watch } from "vue";
import { useStore } from "vuex";
const store = useStore();

const playBtnIcon = ref("ri-pause-circle-line");
const audioLoading = ref(false);
const pic = ref("");

const flag = computed(() => {
    return store.state.menuToggle;
});

const playlistToggle = () => {
    store.commit("playlistToggle");
};

const nowPlay = computed(() => {
    return store.state.nowPlay;
});

const url = computed(() => {
    return `http://music.163.com/song/media/outer/url?id=${nowPlay.value.id}`;
});

const playBtn = () => {
    let audio = document.querySelector("#Audio");
    audio.paused ? audio.play() : audio.pause();
};

watch(
    nowPlay,
    val => {
        Promise.any([
            `https://p1.music.126.net/${val.pic}.jpg?param=80y80`,
            `https://p2.music.126.net/${val.pic}.jpg?param=80y80`,
            `https://p3.music.126.net/${val.pic}.jpg?param=80y80`,
            `https://p4.music.126.net/${val.pic}.jpg?param=80y80`
        ]).then(res => {
            pic.value = res;
        });
    },
    {
        deep: true
    }
);

onMounted(() => {
    let audio = document.querySelector("#Audio");
    audio.onpause = () => {
        playBtnIcon.value = "ri-play-circle-line";
    };
    audio.onplay = () => {
        playBtnIcon.value = "ri-pause-circle-line";
    };
    audio.onloadstart = () => {
        audioLoading.value = true;
    };
    audio.oncanplay = () => {
        audioLoading.value = false;
    };
});
</script>

<style lang="less" scoped>
.player {
    box-shadow: 0 0 15px #aaa;
    position: fixed;
    left: 210px;
    right: 20px;
    bottom: 20px;
    height: 100px;
    border-radius: 8px;
    z-index: 3;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 20px 14px;
    box-sizing: border-box;
    transition: 0.3s;
    .player_left {
        position: relative;
        .player_info {
            width: 250px;
            position: absolute;
            left: 100px;
            top: 50%;
            transform: translateY(-50%);
            line-height: 28px;
            overflow: hidden;
            h3,
            p {
                overflow: hidden;
                white-space: nowrap;
                text-overflow: ellipsis;
                -o-text-overflow: ellipsis;
            }
        }
    }
    .player_btn {
        display: flex;
        align-items: center;
        li {
            width: 45px;
            height: 45px;
            line-height: 45px;
            text-align: center;
            font-size: 35px;
            margin: 0 15px;
            transition: 0.3s;
            transform: scale(0.9);

            &:nth-child(2) {
                width: 60px;
                height: 60px;
                line-height: 60px;
                font-size: 50px;
            }

            &:hover {
                background: rgba(200, 200, 200, 0.3);
                border-radius: 50%;
                opacity: 8;
                box-shadow: inset 0 0 3px var(--el-color-primary);
                color: var(--el-color-primary);
                transform: scale(1);
            }
            &:active {
                color: var(--el-color-primary-dark-2);
                transform: scale(0.8);
            }
        }
    }
    .el-image {
        width: 80px;
        height: 80px;
        border-radius: 5px;
        .image-slot {
            display: flex;
            justify-content: center;
            align-items: center;
            width: 100%;
            height: 100%;
            background: var(--el-fill-color-light);
            color: var(--el-text-color-secondary);
            font-size: 30px;
            .el-icon {
                font-size: 30px;
            }
        }
    }
}
</style>
